1	const PROCESSING_FEE = 5;
2	const FIRST_INSURANCE_RATE = 0.1;
3	
4	const BASE_PREMIUMS: Record<string, number> = {
5	  sword: 100,
6	  amulet: 60,
7	  staff: 80,
8	  potion: 40,
9	  rune: 25,
10	  moonstone: 25,
11	};
12	
13	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
14	
15	type Item = { type: string; cursed?: boolean; enchantment?: number; material?: string };
16	type Damage = { itemType: string; amount: number };
17	type Incident = { cause: string; damages: Damage[] };
18	type QuoteStep = { op: "quote"; items: Item[] };
19	type ClaimStep = { op: "claim"; policy: number; incident: Incident };
20	type Step = QuoteStep | ClaimStep;
21	type Scenario = { customer: { yearsWithMHPCO: number }; steps: Step[] };
22	
23	const DEDUCTIBLE_PER_DAMAGE = 100;
24	const HIGH_ENCHANTMENT_COVERAGE_THRESHOLD = 8;
25	const HIGH_ENCHANTMENT_COVERAGE_RATE = 0.5;
26	
27	const reimbursableAmount = (item: Item, damageAmount: number): number => {
28	  if ((item.enchantment ?? 0) >= HIGH_ENCHANTMENT_COVERAGE_THRESHOLD) {
29	    return damageAmount * HIGH_ENCHANTMENT_COVERAGE_RATE;
30	  }
31	  return damageAmount;
32	};
33	
34	const claimStep = (step: ClaimStep, policyItems: Item[]): { payout: number } => {
35	  const payout = step.incident.damages.reduce((sum, d) => {
36	    const item = policyItems.find((i) => i.type === d.itemType);
37	    if (item === undefined) {
38	      throw new Error(`Claim references item type not in policy: ${d.itemType}`);
39	    }
40	    const reimbursable = reimbursableAmount(item, d.amount);
41	    return sum + (reimbursable - DEDUCTIBLE_PER_DAMAGE);
42	  }, 0);
43	  return { payout: Math.floor(payout) };
44	};
45	
46	const itemBasePremium = (item: Item): number => {
47	  const base = BASE_PREMIUMS[item.type];
48	  if (base === undefined) {
49	    throw new Error(`Unknown item type: ${item.type}`);
50	  }
51	  return base;
52	};
53	
54	const BLOCK_SIZE = 3;
55	const COMPONENT_BLOCK_PRICE = 60;
56	
57	const isComponent = (item: Item): boolean => COMPONENT_TYPES.has(item.type);
58	
59	const sumItemBasePremiums = (items: Item[]): number =>
60	  items.reduce((sum, item) => sum + itemBasePremium(item), 0);
61	
62	const groupByType = (items: Item[]): Map<string, Item[]> => {
63	  const groups = new Map<string, Item[]>();
64	  for (const item of items) {
65	    const group = groups.get(item.type) ?? [];
66	    group.push(item);
67	    groups.set(item.type, group);
68	  }
69	  return groups;
70	};
71	
72	const priceComponentGroup = (group: Item[]): number =>
73	  group.length === BLOCK_SIZE ? COMPONENT_BLOCK_PRICE : sumItemBasePremiums(group);
74	
75	const computeBasePremium = (items: Item[]): number => {
76	  const components = items.filter(isComponent);
77	  const nonComponents = items.filter((item) => !isComponent(item));
78	  const componentGroups = [...groupByType(components).values()];
79	  const componentTotal = componentGroups.reduce(
80	    (sum, group) => sum + priceComponentGroup(group),
81	    0,
82	  );
83	  return sumItemBasePremiums(nonComponents) + componentTotal;
84	};
85	
86	const CURSE_SURCHARGE_RATE = 0.5;
87	const HIGH_ENCHANTMENT_SURCHARGE_RATE = 0.3;
88	const HIGH_ENCHANTMENT_THRESHOLD = 5;
89	
90	const itemSurcharge = (item: Item): number => {
91	  const base = itemBasePremium(item);
92	  const curse = item.cursed ? base * CURSE_SURCHARGE_RATE : 0;
93	  const enchantment =
94	    (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD
95	      ? base * HIGH_ENCHANTMENT_SURCHARGE_RATE
96	      : 0;
97	  return curse + enchantment;
98	};
99	
100	const sumItemSurcharges = (items: Item[]): number =>
101	  items.reduce((sum, item) => sum + itemSurcharge(item), 0);
102	
103	const LOYALTY_DISCOUNT_RATE = 0.2;
104	const LOYALTY_THRESHOLD_YEARS = 2;
105	
106	type Customer = { yearsWithMHPCO: number };
107	type PolicyContext = { customer: Customer; contractIndex: number };
108	
109	const loyaltyDiscount = (base: number, customer: Customer): number =>
110	  customer.yearsWithMHPCO >= LOYALTY_THRESHOLD_YEARS ? base * LOYALTY_DISCOUNT_RATE : 0;
111	
112	const FOLLOW_UP_DISCOUNT_RATE = 0.15;
113	
114	const followUpDiscount = (base: number, contractIndex: number): number =>
115	  contractIndex > 0 ? base * FOLLOW_UP_DISCOUNT_RATE : 0;
116	
117	const sumPolicyDiscounts = (base: number, ctx: PolicyContext): number =>
118	  loyaltyDiscount(base, ctx.customer) + followUpDiscount(base, ctx.contractIndex);
119	
120	const sumPolicySurcharges = (base: number): number => base * FIRST_INSURANCE_RATE;
121	
122	const quoteStep = (step: QuoteStep, ctx: PolicyContext): { premium: number } => {
123	  const base = computeBasePremium(step.items);
124	  const surcharges = sumItemSurcharges(step.items) + sumPolicySurcharges(base);
125	  const discounts = sumPolicyDiscounts(base, ctx);
126	  return {
127	    premium: Math.ceil(base + surcharges - discounts + PROCESSING_FEE),
128	  };
129	};
130	
131	export const runScenario = (scenario: unknown): unknown => {
132	  const { customer, steps } = scenario as Scenario;
133	  let contractIndex = 0;
134	  const policies = new Map<number, Item[]>();
135	  const results = steps.map((step, index) => {
136	    if (step.op === "claim") {
137	      const policyItems = policies.get(step.policy) ?? [];
138	      return claimStep(step, policyItems);
139	    }
140	    policies.set(index, step.items);
141	    const result = quoteStep(step, { customer, contractIndex });
142	    contractIndex += 1;
143	    return result;
144	  });
145	  return { results };
146	};
